from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples into a single fluent, natural‑language sentence.
    Uses predicate‑specific phrasing where possible and joins multiple clauses
    with semicolons for readability.
    """
    if not triples:
        return ""

    def render(t: Triple) -> str:
        s, p, o = t.subject, t.predicate, t.object
        # Strip surrounding quotes from object values
        if o.startswith('"') and o.endswith('"'):
            o = o[1:-1]

        # Predicate‑specific renderings
        if p == "birthPlace":
            return f"{s} was born in {o}"
        if p == "birthDate":
            return f"{s} was born on {o}"
        if p == "deathPlace":
            return f"{s} died in {o}"
        if p in ("deathDate", "deathYear"):
            return f"{s} died on {o}"
        if p == "nationality":
            return f"{s} is a {o}"
        if p == "party":
            return f"{s} belongs to the {o} party"
        if p == "office":
            return f"{s} held the office of {o}"
        if p == "spouse":
            return f"{s} was married to {o}"
        if p == "successor":
            return f"{s} was succeeded by {o}"
        if p == "predecessor":
            return f"{s} succeeded {o}"
        if p == "region":
            return f"{s} is from the region of {o}"
        if p == "residence":
            return f"{s} resides at {o}"
        if p == "country":
            return f"{s} is from {o}"
        if p == "capital":
            return f"{o} is the capital of {s}"
        if p == "largestCity":
            return f"The largest city of {s} is {o}"
        if p == "currency":
            return f"The currency of {s} is {o}"
        if p in ("language", "officialLanguage"):
            return f"The official language of {s} is {o}"
        if p == "leader":
            return f"The leader of {s} is {o}"
        if p == "battle":
            return f"{s} fought in the {o}"
        if p == "award":
            return f"{s} received the {o}"
        if p == "profession":
            return f"{s} was a {o}"
        if p == "religion":
            return f"{s} practiced {o}"
        # Default fallback
        return f"{s} {p} {o}"

    # Render each triple
    clauses = [render(t) for t in triples]

    # Combine clauses into one sentence
    if len(clauses) == 1:
        sentence = clauses[0] + "."
    else:
        sentence = "; ".join(clauses[:-1]) + "; and " + clauses[-1] + "."

    # Capitalise the first character
    sentence = sentence[0].upper() + sentence[1:]
    return sentence

# EVOLVE-BLOCK-END

